mapper.select:
SELECT productName, SUM(salesVolume) AS salesVolume, SUM(salesAmount) AS salesAmount FROM ( SELECT product_name AS productName, SUM(quantity) AS salesVolume, SUM(subtotal) AS salesAmount FROM sys_order_item WHERE create_time BETWEEN #{beginTime} AND #{endTime} GROUP BY product_id, product_name
UNION ALL
SELECT package_name AS productName, SUM(quantity) AS salesVolume, SUM(subtotal) AS salesAmount FROM sys_order_package_item opi INNER JOIN sys_order o ON opi.order_id = o.order_id WHERE o.create_time BETWEEN #{beginTime} AND #{endTime} AND o.status IN ('1', '2') GROUP BY package_id, package_name ) AS combined GROUP BY productName ORDER BY salesVolume DESC LIMIT #{limit}
